239	func codexQuotaCacheComplete(snap *codexharness.CodexQuotaSnapshot) bool {
240		return snap != nil &&
241			!snap.CapturedAt.IsZero() &&
242			strings.TrimSpace(snap.Source) != "" &&
243			len(snap.Windows) > 0 &&
244			snap.Account != nil &&
245			strings.TrimSpace(snap.Account.PlanType) != ""
246	}
