389	// probeServiceProvider pings a provider and returns (status, modelCount, capabilities).
390	func probeServiceProvider(ctx context.Context, entry ServiceProviderEntry) (status string, modelCount int, caps []string) {
391		probe := probeServiceProviderDetailed(ctx, entry)
392		return probe.status, probe.modelCount, probe.caps
393	}
394	
395	func probeServiceProviderDetailed(ctx context.Context, entry ServiceProviderEntry) providerProbeResult {
396		switch entry.Type {
397		case "anthropic":
398			if entry.APIKey == "" {
399				return providerProbeResult{status: "error: api_key not configured", detail: "api_key not configured"}
400			}
401			// Anthropic does not expose an unauthenticated /v1/models list endpoint.
402			// Treat key presence as the connectivity signal.
403			return providerProbeResult{status: "connected", caps: providerCapabilities(entry)}
404	
405		case "openai", "openrouter", "lmstudio", "llama-server", "ds4", "omlx", "rapid-mlx", "vllm", "ollama", "minimax", "qwen", "zai", "":
406			if entry.BaseURL == "" {
407				return providerProbeResult{status: "error: base_url not configured", detail: "base_url not configured"}
408			}
409			n, err := discoverOpenAIModels(ctx, entry.BaseURL, entry.APIKey)
410			if err != nil {
411				msg := err.Error()
412				if serviceIsUnreachable(msg) {
413					return providerProbeResult{status: "unreachable", detail: serviceTrimError(msg)}
414				}
415				detail := serviceTrimError(msg)
416				return providerProbeResult{status: "error: " + detail, detail: detail}
417			}
418			return providerProbeResult{status: "connected", modelCount: n, caps: providerCapabilities(entry)}
419	
420		default:
421			detail := "unknown provider type " + entry.Type
422			return providerProbeResult{status: "error: " + detail, detail: detail}
423		}
424	}
425	
426	func probeProviderStatus(ctx context.Context, entry ServiceProviderEntry, capturedAt time.Time) providerProbeResult {
427		endpoints := modelDiscoveryEndpoints(entry)
428		if len(endpoints) == 0 {
429			probe := probeServiceProviderDetailed(ctx, entry)
430			probe.endpointStatuses = providerEndpointStatusesFromProbe(entry, probe, capturedAt)
431			return probe
432		}
433	
434		statuses := make([]EndpointStatus, 0, len(endpoints))
435		var aggregate providerProbeResult
436		aggregate.status = "error: endpoint probe did not run"
437		for _, endpoint := range endpoints {
438			endpointEntry := entry
439			endpointEntry.BaseURL = endpoint.BaseURL
440			endpointProbe := probeServiceProviderDetailed(ctx, endpointEntry)
441			endpointProbe.endpointName = endpoint.Name
442			endpointProbe.baseURL = endpoint.BaseURL
443			statuses = append(statuses, endpointStatusFromProbe(endpoint.Name, endpoint.BaseURL, endpointProbe, capturedAt))
444			if endpointProbe.status == "connected" {
445				if aggregate.status != "connected" {
446					aggregate.status = "connected"
447					aggregate.caps = append([]string(nil), endpointProbe.caps...)
448					aggregate.detail = ""
449				}
450				aggregate.modelCount += endpointProbe.modelCount
451				continue
452			}
453			if aggregate.status == "connected" {
454				continue
455			}
456			if shouldPreferProviderProbe(endpointProbe, aggregate) {
457				aggregate.status = endpointProbe.status
458				aggregate.detail = endpointProbe.detail
459				aggregate.caps = append([]string(nil), endpointProbe.caps...)
460				aggregate.baseURL = endpointProbe.baseURL
461				aggregate.endpointName = endpointProbe.endpointName
462			}
463		}
464		aggregate.endpointStatuses = statuses
465		return aggregate
466	}
467	
468	func shouldPreferProviderProbe(candidate, current providerProbeResult) bool {
469		return providerProbePriority(candidate.status) < providerProbePriority(current.status)
470	}
471	
472	func providerProbePriority(status string) int {
473		switch endpointStatus(status) {
474		case "connected":
475			return 0
476		case "unauthenticated":
477			return 1
478		case "unreachable":
479			return 2
480		default:
481			return 3
482		}
483	}
