125	func (s *service) startPrimaryQuotaRefreshWorker() {
126		if s == nil || s.opts.QuotaRefreshInterval <= 0 {
127			return
128		}
129		ctx := s.opts.QuotaRefreshContext
130		if ctx == nil {
131			ctx = context.Background()
132		}
133		interval := s.opts.QuotaRefreshInterval
134		go func() {
135			ticker := time.NewTicker(interval)
136			defer ticker.Stop()
137			for {
138				select {
139				case <-ctx.Done():
140					return
141				case <-ticker.C:
142					s.ensurePrimaryQuotaRefresh(ctx, quotaRefreshAsync)
143				}
144			}
145		}()
146	}
