148	func requestPrimaryQuotaRefresh(ctx context.Context, harnessName string, policy quotaRefreshPolicy) <-chan struct{} {
149		done := make(chan struct{})
150		if ctx == nil {
151			ctx = context.Background()
152		}
153		if ctx.Err() != nil {
154			close(done)
155			return nil
156		}
157	
158		now := time.Now()
159		primaryQuotaRefresh.mu.Lock()
160		if primaryQuotaRefresh.inFlight[harnessName] {
161			primaryQuotaRefresh.mu.Unlock()
162			close(done)
163			return nil
164		}
165		if last := primaryQuotaRefresh.lastAttempt[harnessName]; !last.IsZero() && now.Sub(last) < policy.debounce {
166			primaryQuotaRefresh.mu.Unlock()
167			close(done)
168			return nil
169		}
170		primaryQuotaRefresh.lastAttempt[harnessName] = now
171		primaryQuotaRefresh.inFlight[harnessName] = true
172		primaryQuotaRefresh.mu.Unlock()
173	
174		go func() {
175			defer close(done)
176			defer func() {
177				primaryQuotaRefresh.mu.Lock()
178				primaryQuotaRefresh.inFlight[harnessName] = false
179				primaryQuotaRefresh.mu.Unlock()
180			}()
181	
182			switch harnessName {
183			case "claude":
184				refreshClaudeQuotaCache(ctx, policy.debounce, policy.probeTimeout)
185			case "codex":
186				refreshCodexQuotaCache(ctx, policy.debounce, policy.probeTimeout)
187			}
188		}()
189		return done
190	}
