192	func waitForPrimaryQuotaRefreshes(waits []<-chan struct{}, timeout time.Duration) {
193		deadline := time.After(timeout)
194		for _, done := range waits {
195			select {
196			case <-done:
197			case <-deadline:
198				return
199			}
200		}
201	}
