395	func probeServiceProviderDetailed(ctx context.Context, entry ServiceProviderEntry) providerProbeResult {
396		switch entry.Type {
397		case "anthropic":
398			if entry.APIKey == "" {
399				return providerProbeResult{status: "error: api_key not configured", detail: "api_key not configured"}
400			}
401			// Anthropic does not expose an unauthenticated /v1/models list endpoint.
402			// Treat key presence as the connectivity signal.
403			return providerProbeResult{status: "connected", caps: providerCapabilities(entry)}
404	
405		case "openai", "openrouter", "lmstudio", "llama-server", "ds4", "omlx", "rapid-mlx", "vllm", "ollama", "minimax", "qwen", "zai", "":
406			if entry.BaseURL == "" {
407				return providerProbeResult{status: "error: base_url not configured", detail: "base_url not configured"}
408			}
409			n, err := discoverOpenAIModels(ctx, entry.BaseURL, entry.APIKey)
410			if err != nil {
411				msg := err.Error()
412				if serviceIsUnreachable(msg) {
413					return providerProbeResult{status: "unreachable", detail: serviceTrimError(msg)}
414				}
415				detail := serviceTrimError(msg)
416				return providerProbeResult{status: "error: " + detail, detail: detail}
417			}
418			return providerProbeResult{status: "connected", modelCount: n, caps: providerCapabilities(entry)}
419	
420		default:
421			detail := "unknown provider type " + entry.Type
422			return providerProbeResult{status: "error: " + detail, detail: detail}
423		}
424	}
