426	func probeProviderStatus(ctx context.Context, entry ServiceProviderEntry, capturedAt time.Time) providerProbeResult {
427		endpoints := modelDiscoveryEndpoints(entry)
428		if len(endpoints) == 0 {
429			probe := probeServiceProviderDetailed(ctx, entry)
430			probe.endpointStatuses = providerEndpointStatusesFromProbe(entry, probe, capturedAt)
431			return probe
432		}
433	
434		statuses := make([]EndpointStatus, 0, len(endpoints))
435		var aggregate providerProbeResult
436		aggregate.status = "error: endpoint probe did not run"
437		for _, endpoint := range endpoints {
438			endpointEntry := entry
439			endpointEntry.BaseURL = endpoint.BaseURL
440			endpointProbe := probeServiceProviderDetailed(ctx, endpointEntry)
441			endpointProbe.endpointName = endpoint.Name
442			endpointProbe.baseURL = endpoint.BaseURL
443			statuses = append(statuses, endpointStatusFromProbe(endpoint.Name, endpoint.BaseURL, endpointProbe, capturedAt))
444			if endpointProbe.status == "connected" {
445				if aggregate.status != "connected" {
446					aggregate.status = "connected"
447					aggregate.caps = append([]string(nil), endpointProbe.caps...)
448					aggregate.detail = ""
449				}
450				aggregate.modelCount += endpointProbe.modelCount
451				continue
452			}
453			if aggregate.status == "connected" {
454				continue
455			}
456			if shouldPreferProviderProbe(endpointProbe, aggregate) {
457				aggregate.status = endpointProbe.status
458				aggregate.detail = endpointProbe.detail
459				aggregate.caps = append([]string(nil), endpointProbe.caps...)
460				aggregate.baseURL = endpointProbe.baseURL
461				aggregate.endpointName = endpointProbe.endpointName
462			}
463		}
464		aggregate.endpointStatuses = statuses
465		return aggregate
466	}
