537	func serviceIsUnreachable(msg string) bool {
538		lower := strings.ToLower(msg)
539		return strings.Contains(lower, "connection refused") ||
540			strings.Contains(lower, "no such host") ||
541			strings.Contains(lower, "dial tcp") ||
542			strings.Contains(lower, "unreachable") ||
543			strings.Contains(lower, "connection reset") ||
544			strings.Contains(lower, "i/o timeout")
