195	// claudeQuotaStatusFromSnapshot projects the per-harness snapshot onto
196	// harnesses.QuotaStatus, deriving State and RoutingPreference via the
197	// existing DecideClaudeQuotaRouting helper so today's "PreferClaude +
198	// freshness" semantics map cleanly onto CONTRACT-004's RoutingPreference
199	// enum.
200	func claudeQuotaStatusFromSnapshot(snap *ClaudeQuotaSnapshot, now time.Time) harnesses.QuotaStatus {
201		decision := DecideClaudeQuotaRouting(snap, now, claudeQuotaFreshness)
202		pref, state := mapClaudeRoutingPreference(decision)
203		status := harnesses.QuotaStatus{
204			Source:            snap.Source,
205			CapturedAt:        snap.CapturedAt,
206			Fresh:             decision.Fresh,
207			Age:               decision.Age,
208			State:             state,
209			Windows:           append([]harnesses.QuotaWindow(nil), snap.Windows...),
210			RoutingPreference: pref,
211			Reason:            quotaReasonForProjection(decision, state),
212		}
213		if snap.Account != nil {
214			acct := claudeAccountSnapshotFromQuotaSnapshot(snap, now)
215			status.Account = &acct
216		}
217		return status
218	}
219	
220	// quotaReasonForProjection trims the routing decision's diagnostic
221	// reason so QuotaStatus.Reason carries information only when it adds
222	// value beyond the State enum. The trivial QuotaOK success path
223	// ("fresh snapshot has headroom") is suppressed so the public Status
224	// string matches the contract-003 fixture (bare "ok"). All non-OK
225	// states keep the decision reason because it surfaces why the state is
226	// not ok (stale snapshot, incomplete account, exhausted window).
227	func quotaReasonForProjection(decision ClaudeQuotaRoutingDecision, state harnesses.QuotaStateValue) string {
228		if state == harnesses.QuotaOK {
229			return ""
230		}
231		return decision.Reason
232	}
233	
234	// mapClaudeRoutingPreference translates today's PreferClaude+freshness
235	// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
236	// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
237	// stale ⇒ Stale/Blocked ("assume limited"); fresh+PreferClaude ⇒
238	// OK/Available; fresh+!PreferClaude ⇒ Blocked/Blocked.
239	func mapClaudeRoutingPreference(d ClaudeQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
240		if !d.SnapshotPresent {
241			return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
242		}
243		if !d.Fresh {
244			return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
245		}
246		if d.PreferClaude {
247			return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
248		}
249		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
250	}
251	
252	// claudeAccountSnapshotFromQuotaSnapshot derives an AccountSnapshot from
253	// the quota cache's embedded Account field. Plan-type "unknown" (written
254	// by MarkClaudeQuotaExhaustedFromMessage on runtime errors) is reported
255	// as unauthenticated evidence rather than positive authentication.
256	func claudeAccountSnapshotFromQuotaSnapshot(snap *ClaudeQuotaSnapshot, now time.Time) harnesses.AccountSnapshot {
257		out := harnesses.AccountSnapshot{
258			Source:     "cache",
259			CapturedAt: snap.CapturedAt,
260			Fresh:      IsClaudeQuotaFresh(snap, now, claudeAccountFreshness),
261		}
262		if snap.Account == nil {
263			return out
264		}
265		plan := strings.TrimSpace(snap.Account.PlanType)
266		out.PlanType = plan
267		out.Email = snap.Account.Email
268		out.OrgName = snap.Account.OrgName
269		switch {
270		case plan == "" || strings.EqualFold(plan, "unknown"):
271			out.Unauthenticated = true
272		default:
273			out.Authenticated = true
274		}
275		return out
276	}
