11	// Test builds expose the four CONTRACT-003 seams via embedded seamOptions.
12	// Each helper returns the configured hook (possibly nil) and the native
13	// provider resolver consults FakeProvider to bypass real HTTP.
14	
15	// promptAssertionHookFn / compactionAssertionHookFn / toolWiringHookFn
16	// are the function-typed aliases shared by service_execute.go. In test
17	// builds they alias the seam types from testseam_types.go.
18	type promptAssertionHookFn = PromptAssertionHook
19	type compactionAssertionHookFn = CompactionAssertionHook
20	type toolWiringHookFn = ToolWiringHook
21	
22	func (s *service) promptAssertionHook() promptAssertionHookFn {
23		return s.opts.PromptAssertionHook
24	}
25	
26	func (s *service) compactionAssertionHook() compactionAssertionHookFn {
27		return s.opts.CompactionAssertionHook
28	}
29	
30	func (s *service) toolWiringHook() toolWiringHookFn {
31		return s.opts.ToolWiringHook
32	}
33	
34	func (s *service) resolveNativeProvider(req ServiceExecuteRequest) nativeProviderResolution {
35		if s.opts.FakeProvider != nil {
36			return nativeProviderResolution{
37				Provider: &fakeProviderAdapter{fp: s.opts.FakeProvider},
38				Name:     req.Provider,
39				Entry:    ServiceProviderEntry{Model: req.Model},
40			}
41		}
42		return s.resolveConfiguredNativeProvider(req)
43	}
44	
45	// fakeProviderAdapter wraps a *FakeProvider so it satisfies the
46	// core.Provider interface. Static responses are consumed in order;
47	// Dynamic is invoked per call when set; InjectError fires per-call to
48	// optionally return an error before the response.
49	type fakeProviderAdapter struct {
50		fp        *FakeProvider
51		callIndex int
52	}
53	
54	func (a *fakeProviderAdapter) Chat(ctx context.Context, messages []agentcore.Message, tools []agentcore.ToolDef, opts agentcore.Options) (agentcore.Response, error) {
55		defer func() { a.callIndex++ }()
56		if a.fp == nil {
57			return agentcore.Response{}, nil
58		}
59		if a.fp.InjectError != nil {
60			if err := a.fp.InjectError(a.callIndex); err != nil {
61				return agentcore.Response{}, err
62			}
63		}
64		if a.fp.Dynamic != nil {
65			toolNames := make([]string, len(tools))
66			for i, t := range tools {
67				toolNames[i] = t.Name
68			}
69			freq := FakeRequest{
70				Messages:    messages,
71				Tools:       toolNames,
72				Model:       opts.Model,
73				Temperature: opts.Temperature,
74				Seed:        opts.Seed,
75				Reasoning:   opts.Reasoning,
76			}
77			fresp, err := a.fp.Dynamic(freq)
78			if err != nil {
79				return agentcore.Response{}, err
80			}
81			return fakeResponseToResponse(fresp), nil
82		}
83		if a.callIndex < len(a.fp.Static) {
84			return fakeResponseToResponse(a.fp.Static[a.callIndex]), nil
85		}
86		// Out of static script — return an empty response so the loop
87		// terminates with no further tool calls.
88		return agentcore.Response{Content: "", Usage: agentcore.TokenUsage{}}, nil
89	}
90	
91	func fakeResponseToResponse(fr FakeResponse) agentcore.Response {
92		return agentcore.Response{
93			Content:   fr.Text,
94			ToolCalls: fr.ToolCalls,
95			Usage:     fr.Usage,
96		}
97	}
