90	func (s *service) ensurePrimaryQuotaRefresh(ctx context.Context, mode quotaRefreshMode) {
91		policy := s.quotaRefreshPolicy()
92		var waits []<-chan struct{}
93		for _, name := range []string{"claude", "codex"} {
94			status := primaryQuotaCacheStatus(name, policy.debounce)
95			if !status.needsRefresh {
96				continue
97			}
98			done := requestPrimaryQuotaRefresh(ctx, name, policy)
99			if mode == quotaRefreshStartup && !status.usable && done != nil {
100				waits = append(waits, done)
101			}
102		}
103		if mode == quotaRefreshStartup && len(waits) > 0 && policy.startupWait > 0 {
104			waitForPrimaryQuotaRefreshes(waits, policy.startupWait)
105		}
106	}
