203	func primaryQuotaCacheStatus(harnessName string, debounce time.Duration) quotaCacheStatus {
204		now := time.Now()
205		switch harnessName {
206		case "claude":
207			cachePath, err := claudeharness.ClaudeQuotaCachePath()
208			if err != nil {
209				return quotaCacheStatus{}
210			}
211			snap, _ := claudeharness.ReadClaudeQuotaFrom(cachePath)
212			if snap == nil {
213				return quotaCacheStatus{needsRefresh: true}
214			}
215			decision := claudeharness.DecideClaudeQuotaRouting(snap, now, debounce)
216			return quotaCacheStatus{
217				needsRefresh: !decision.Fresh,
218				usable:       decision.Fresh,
219			}
220		case "codex":
221			cachePath, err := codexharness.CodexQuotaCachePath()
222			if err != nil {
223				return quotaCacheStatus{}
224			}
225			snap, _ := codexharness.ReadCodexQuotaFrom(cachePath)
226			if snap == nil {
227				return quotaCacheStatus{needsRefresh: true}
228			}
229			decision := codexharness.DecideCodexQuotaRouting(snap, now, debounce)
230			return quotaCacheStatus{
231				needsRefresh: !decision.Fresh || !codexQuotaCacheComplete(snap),
232				usable:       decision.Fresh && decision.PreferCodex,
233			}
234		default:
235			return quotaCacheStatus{}
236		}
237	}
