485	// discoverOpenAIModels queries the /v1/models endpoint and returns the model count.
486	// This is a minimal inline version of provider/openai.DiscoverModels that avoids
487	// the import cycle (provider/openai imports the root agent package).
488	func discoverOpenAIModels(ctx context.Context, baseURL, apiKey string) (int, error) {
489		base := strings.TrimRight(baseURL, "/")
490		endpoint := base + "/models"
491	
492		req, err := http.NewRequestWithContext(ctx, http.MethodGet, endpoint, nil)
493		if err != nil {
494			return 0, fmt.Errorf("discovery: build request: %w", err)
495		}
496		req.Header.Set("Accept", "application/json")
497		if apiKey != "" {
498			req.Header.Set("Authorization", "Bearer "+apiKey)
499		}
500	
501		resp, err := http.DefaultClient.Do(req)
502		if err != nil {
503			return 0, err
504		}
505		defer resp.Body.Close()
506	
507		if resp.StatusCode != http.StatusOK {
508			body, _ := io.ReadAll(io.LimitReader(resp.Body, 512))
509			return 0, fmt.Errorf("discovery: %s returned HTTP %d: %s", endpoint, resp.StatusCode, strings.TrimSpace(string(body)))
510		}
511	
512		var mr struct {
513			Data []struct {
514				ID string `json:"id"`
515			} `json:"data"`
516		}
517		if err := json.NewDecoder(resp.Body).Decode(&mr); err != nil {
518			return 0, fmt.Errorf("discovery: decode response from %s: %w", endpoint, err)
519		}
520		return len(mr.Data), nil
521	}
