592	// healthCheckRefreshClaudeQuota refreshes the Claude direct PTY quota cache when
593	// the cached snapshot is older than the default refresh debounce. It is a
594	// best-effort operation: errors are silently discarded so that a claude absence
595	// does not fail HealthCheck.
596	func healthCheckRefreshClaudeQuota(ctx context.Context) {
597		refreshClaudeQuotaCache(ctx, defaultQuotaRefreshDebounce, defaultQuotaRefreshProbeTimeout)
598	}
599	
600	func refreshClaudeQuotaCache(_ context.Context, debounce, timeout time.Duration) {
601		cachePath, err := claudeharness.ClaudeQuotaCachePath()
602		if err != nil {
603			return
604		}
605	
606		snap, _ := claudeharness.ReadClaudeQuotaFrom(cachePath)
607		if snap != nil && claudeharness.DecideClaudeQuotaRouting(snap, time.Now(), debounce).Fresh {
608			// Cache is fresh enough; skip the expensive PTY probe.
609			return
610		}
611	
612		// Cache is absent or stale - run a direct PTY probe with a bounded timeout.
613		windows, acct, probeErr := callHealthCheckClaudeQuotaRefresher(timeout)
614		if probeErr != nil || len(windows) == 0 {
615			return
616		}
617	
618		// Convert QuotaWindow slice to ClaudeQuotaSnapshot. The PTY path returns
619		// percent-based windows; synthesise remaining counts from UsedPercent.
620		newSnap := claudeharness.ClaudeQuotaSnapshot{
621			CapturedAt: time.Now().UTC(),
622			Source:     "pty",
623			Account:    acct,
624			Windows:    append([]harnesses.QuotaWindow(nil), windows...),
625		}
626		for _, w := range windows {
627			switch w.LimitID {
628			case "session":
629				// 5-hour window; use a nominal limit of 100 so Remaining = 100-Used.
630				used := int(w.UsedPercent)
631				newSnap.FiveHourLimit = 100
632				newSnap.FiveHourRemaining = 100 - used
633			case "weekly-all", "weekly-sonnet":
634				used := int(w.UsedPercent)
635				newSnap.WeeklyLimit = 100
636				newSnap.WeeklyRemaining = 100 - used
637			}
638		}
639	
640		_ = claudeharness.WriteClaudeQuota(cachePath, newSnap)
641	}
642	
643	func healthCheckRefreshCodexQuota(ctx context.Context) {
644		refreshCodexQuotaCache(ctx, defaultQuotaRefreshDebounce, defaultQuotaRefreshProbeTimeout)
645	}
646	
647	func refreshCodexQuotaCache(_ context.Context, debounce, timeout time.Duration) {
648		cachePath, err := codexharness.CodexQuotaCachePath()
649		if err != nil {
650			return
651		}
652	
653		snap, _ := codexharness.ReadCodexQuotaFrom(cachePath)
654		if snap != nil && codexharness.IsCodexQuotaFresh(snap, time.Now(), debounce) && codexQuotaCacheComplete(snap) {
655			return
656		}
657	
658		if sessionSnap, ok := callHealthCheckCodexSessionQuotaReader(); ok && codexSessionQuotaUsable(sessionSnap, debounce) {
659			_ = codexharness.WriteCodexQuota(cachePath, *sessionSnap)
660			return
661		}
662	
663		windows, probeErr := callHealthCheckCodexQuotaRefresher(timeout)
664		if probeErr != nil || len(windows) == 0 {
665			return
666		}
667	
668		_ = codexharness.WriteCodexQuota(cachePath, codexharness.CodexQuotaSnapshot{
669			CapturedAt: time.Now().UTC(),
670			Windows:    windows,
671			Source:     "pty",
672		})
673	}
674	
675	func callHealthCheckClaudeQuotaRefresher(timeout time.Duration) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
676		healthCheckQuotaProbeMu.RLock()
677		fn := healthCheckClaudeQuotaRefresher
678		healthCheckQuotaProbeMu.RUnlock()
679		return fn(timeout)
680	}
681	
682	func callHealthCheckCodexQuotaRefresher(timeout time.Duration) ([]harnesses.QuotaWindow, error) {
683		healthCheckQuotaProbeMu.RLock()
684		fn := healthCheckCodexQuotaRefresher
685		healthCheckQuotaProbeMu.RUnlock()
686		return fn(timeout)
687	}
688	
689	func callHealthCheckCodexSessionQuotaReader() (*codexharness.CodexQuotaSnapshot, bool) {
690		healthCheckQuotaProbeMu.RLock()
691		fn := healthCheckCodexSessionQuotaReader
692		healthCheckQuotaProbeMu.RUnlock()
693		return fn()
694	}
695	
696	func codexSessionQuotaUsable(snap *codexharness.CodexQuotaSnapshot, debounce time.Duration) bool {
697		if !codexQuotaCacheComplete(snap) {
698			return false
699		}
700		decision := codexharness.DecideCodexQuotaRouting(snap, time.Now(), debounce)
701		return decision.Fresh && decision.PreferCodex
702	}
