151	// AccountStatus implements harnesses.AccountHarness. Codex reads
152	// non-secret account metadata from auth.json via CodexAuthPath /
153	// ReadCodexAccount; this method projects that onto AccountSnapshot.
154	func (r *Runner) AccountStatus(ctx context.Context, now time.Time) (harnesses.AccountSnapshot, error) {
155		if err := ctx.Err(); err != nil {
156			return harnesses.AccountSnapshot{}, err
157		}
158		return readCodexAccountSnapshot(now), nil
159	}
160	
161	// RefreshAccount implements harnesses.AccountHarness by re-reading the
162	// codex auth file (the source of account evidence) and projecting onto
163	// AccountSnapshot. Single-flight per harness via the package-scoped
164	// singleflight group.
165	func (r *Runner) RefreshAccount(ctx context.Context) (harnesses.AccountSnapshot, error) {
166		if err := ctx.Err(); err != nil {
167			return harnesses.AccountSnapshot{}, err
168		}
169		v, err, _ := refreshGroup.Do("refresh-account", func() (any, error) {
170			return readCodexAccountSnapshot(time.Now()), nil
171		})
172		if err != nil {
173			return harnesses.AccountSnapshot{}, err
174		}
175		return v.(harnesses.AccountSnapshot), nil
176	}
177	
178	// AccountFreshness implements harnesses.AccountHarness.
179	func (r *Runner) AccountFreshness() time.Duration {
180		return codexAccountFreshness
181	}
182	
183	// readCodexAccountSnapshot reads codex auth state and projects it onto
184	// AccountSnapshot. A missing or unreadable auth file is reported as
185	// Unauthenticated on a valid snapshot value, not as an error.
186	func readCodexAccountSnapshot(now time.Time) harnesses.AccountSnapshot {
187		snap := harnesses.AccountSnapshot{Source: "cache"}
188		if path, err := CodexAuthPath(); err == nil && path != "" {
189			snap.Source = path
190			if st, statErr := os.Stat(path); statErr == nil {
191				snap.CapturedAt = st.ModTime().UTC()
192				snap.Fresh = now.UTC().Sub(snap.CapturedAt) <= codexAccountFreshness
193			}
194		}
195		account, ok := ReadCodexAccount()
196		if !ok || account == nil {
197			snap.Unauthenticated = true
198			return snap
199		}
200		snap.Email = account.Email
201		snap.PlanType = account.PlanType
202		snap.OrgName = account.OrgName
203		if strings.TrimSpace(account.PlanType) == "" {
204			snap.Unauthenticated = true
205		} else {
206			snap.Authenticated = true
207		}
208		return snap
209	}
210	
211	// DefaultModelSnapshot implements harnesses.ModelDiscoveryHarness.
212	func (r *Runner) DefaultModelSnapshot() harnesses.ModelDiscoverySnapshot {
213		return DefaultCodexModelDiscovery()
214	}
215	
216	// ResolveModelAlias implements harnesses.ModelDiscoveryHarness. Returns
217	// harnesses.ErrAliasNotResolvable when the supplied family is not a
218	// recognized codex alias or when the supplied discovery snapshot has
219	// no concrete model matching the family.
220	func (r *Runner) ResolveModelAlias(family string, snapshot harnesses.ModelDiscoverySnapshot) (string, error) {
221		normalized := strings.ToLower(strings.TrimSpace(family))
222		if !isSupportedCodexAlias(normalized) {
223			return "", harnesses.ErrAliasNotResolvable
224		}
225		resolved := ResolveCodexModelAlias(normalized, snapshot)
226		if resolved == "" || resolved == normalized {
227			// existing helper returns the input string when no concrete
228			// model matches; treat that as unresolvable per CONTRACT-004.
229			return "", harnesses.ErrAliasNotResolvable
230		}
231		return resolved, nil
232	}
233	
234	// SupportedAliases implements harnesses.ModelDiscoveryHarness.
235	func (r *Runner) SupportedAliases() []string {
236		return append([]string(nil), supportedAliases...)
237	}
238	
239	func isSupportedCodexAlias(family string) bool {
240		for _, a := range supportedAliases {
241			if a == family {
242				return true
243			}
244		}
245		return false
246	}
247	
248	// codexQuotaStatusFromSnapshot projects the per-harness snapshot onto
249	// harnesses.QuotaStatus, deriving State and RoutingPreference via the
250	// existing DecideCodexQuotaRouting helper so today's "PreferCodex +
251	// freshness" semantics map cleanly onto CONTRACT-004's RoutingPreference
252	// enum.
253	func codexQuotaStatusFromSnapshot(snap *CodexQuotaSnapshot, now time.Time) harnesses.QuotaStatus {
254		decision := DecideCodexQuotaRouting(snap, now, codexQuotaFreshness)
255		pref, state := mapCodexRoutingPreference(decision)
256		status := harnesses.QuotaStatus{
257			Source:            snap.Source,
258			CapturedAt:        snap.CapturedAt,
259			Fresh:             decision.Fresh,
260			Age:               decision.Age,
261			State:             state,
262			Windows:           append([]harnesses.QuotaWindow(nil), snap.Windows...),
263			RoutingPreference: pref,
264			Reason:            decision.Reason,
265		}
266		if snap.Account != nil {
267			acct := codexAccountSnapshotFromQuotaSnapshot(snap, now)
268			status.Account = &acct
269		}
270		return status
271	}
272	
273	// mapCodexRoutingPreference translates today's PreferCodex+freshness
274	// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
275	// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
276	// stale ⇒ Stale/Blocked ("assume limited"); fresh+PreferCodex ⇒
277	// OK/Available; fresh+!PreferCodex ⇒ Blocked/Blocked.
278	func mapCodexRoutingPreference(d CodexQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
279		if !d.SnapshotPresent {
280			return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
281		}
282		if !d.Fresh {
283			return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
284		}
285		if d.PreferCodex {
286			return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
287		}
288		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
289	}
290	
291	// codexAccountSnapshotFromQuotaSnapshot derives an AccountSnapshot from
292	// the quota cache's embedded Account field. An empty plan-type is
293	// reported as unauthenticated evidence rather than positive
294	// authentication.
295	func codexAccountSnapshotFromQuotaSnapshot(snap *CodexQuotaSnapshot, now time.Time) harnesses.AccountSnapshot {
296		out := harnesses.AccountSnapshot{
297			Source:     "cache",
298			CapturedAt: snap.CapturedAt,
299			Fresh:      IsCodexQuotaFresh(snap, now, codexAccountFreshness),
300		}
301		if snap.Account == nil {
302			return out
303		}
304		plan := strings.TrimSpace(snap.Account.PlanType)
305		out.PlanType = plan
306		out.Email = snap.Account.Email
307		out.OrgName = snap.Account.OrgName
308		if plan == "" {
309			out.Unauthenticated = true
310		} else {
311			out.Authenticated = true
312		}
313		return out
314	}
315	
316	// Compile-time interface satisfaction.
317	var (
318		_ harnesses.Harness               = (*Runner)(nil)
319		_ harnesses.QuotaHarness          = (*Runner)(nil)
320		_ harnesses.AccountHarness        = (*Runner)(nil)
321		_ harnesses.ModelDiscoveryHarness = (*Runner)(nil)
322	)
