		}
		decision := claudeharness.DecideClaudeQuotaRouting(snap, now, debounce)
		return quotaCacheStatus{
			needsRefresh: !decision.Fresh,
			usable:       decision.Fresh,
		}
	case "codex":
		cachePath, err := codexharness.CodexQuotaCachePath()
		if err != nil {
